import Fixture from '../../data/interfaces/fixture';

const SeasonSummary = (props : {fixtures : Fixture[]}) => {

    const {fixtures} = props;

    const totalGames = fixtures.length;
    const totalWins = fixtures.filter(fixture => fixture.result === "W").length;
    const totalDraws = fixtures.filter(fixture => fixture.result === "D").length;
    const totalLosses = fixtures.filter(fixture => fixture.result === "L").length;
    const totalGoals = fixtures.filter(fixture => fixture.npScore).reduce((sum, currentValue) => sum + currentValue.npScore, 0);
    const totalGoalsAgainst = fixtures.filter(fixture => fixture.oppScore).reduce((sum, currentValue) => sum + currentValue.oppScore, 0);
    const goalsDifference = totalGoals - totalGoalsAgainst;
    const totalPoints = fixtures.filter(fixture => fixture.pts).reduce((sum, currentValue) => sum + currentValue.pts, 0);

    return (        
        
        <tr>
            <td>PLD: {totalGames}</td>
            <td>W: {totalWins}</td>
            <td>D: {totalDraws}</td>
            <td>L: {totalLosses}</td>
            <td>GF: {totalGoals}</td>     
            <td>GA: {totalGoalsAgainst}</td>       
            <td>GD: {goalsDifference}</td>
            <td>PTS: {totalPoints}</td>
        </tr>          
    );

}
export default SeasonSummary;
